BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?decisionNode ?name ?guard WHERE {
  ?decisionNode rdf:type vocab:decision%20node .
  ?decisionNode vocab:NamedElement_name ?name .
  OPTIONAL {
    ?edge vocab:ActivityEdge_source ?decisionNode .
    ?edge vocab:ActivityEdge_guard ?guardVal .
    ?guardVal vocab:ValueSpecification_expression ?guard .
  }
}
LIMIT 30

BASE <http://api.koneksys.com/cameo/>
