PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?elem ?name ?type ?comment WHERE {
  ?elem vocab:NamedElement_name ?name . 
  FILTER(CONTAINS(LCASE(STR(?name)), LCASE("guide")) && (CONTAINS(LCASE(STR(?name)), LCASE("loss")) || CONTAINS(LCASE(STR(?name)), LCASE("lost")) || CONTAINS(LCASE(STR(?name)), LCASE("fail")) || CONTAINS(LCASE(STR(?name)), LCASE("reacquir"))))
